const items = $input.all();
const project = $('プロジェクトループ').item.json;

const now = new Date();
const dayOfWeek = now.getDay();
const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const weekStart = new Date(now);
weekStart.setDate(now.getDate() + diffToMonday);
const weekEnd = new Date(weekStart);
weekEnd.setDate(weekStart.getDate() + 6);
const weekStartStr = weekStart.toISOString().split('T')[0];
const weekEndStr = weekEnd.toISOString().split('T')[0];

const reports = items.map(item => {
  const risks = typeof item.json.risks === 'string' ? JSON.parse(item.json.risks || '[]') : (item.json.risks || []);
  return {
    date: String(item.json.report_date).split('T')[0],
    progress: parseFloat(item.json.overall_progress) || 0,
    risks: risks
  };
});

const avgProgress = reports.length > 0
  ? reports.reduce((s, r) => s + r.progress, 0) / reports.length
  : 0;

const progressTrend = reports.length >= 2
  ? reports[reports.length - 1].progress - reports[0].progress
  : 0;

const allRisks = reports.flatMap(r => r.risks);
const riskCounts = allRisks.reduce((acc, r) => {
  acc[r.type] = (acc[r.type] || 0) + 1;
  return acc;
}, {});

const summary = {
  week_start: weekStartStr,
  week_end: weekEndStr,
  avg_progress: Math.round(avgProgress * 100) / 100,
  progress_trend: Math.round(progressTrend * 100) / 100,
  report_count: reports.length,
  high_risks: allRisks.filter(r => r.severity === 'high'),
  risk_counts: riskCounts,
  daily_progression: reports.map(r => ({ date: r.date, progress: r.progress }))
};

const escapeSql = s => String(s).replace(/'/g, "''");

return [{
  json: {
    project_id: project.id,
    week_start_date: weekStartStr,
    week_end_date: weekEndStr,
    summary_sql: escapeSql(JSON.stringify(summary))
  }
}];

const allItems = $input.all();
const today = new Date().toISOString().split('T')[0];

const now = new Date();
const dayOfWeek = now.getDay();
const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const weekStart = new Date(now);
weekStart.setDate(now.getDate() + diffToMonday);
const weekStartStr = weekStart.toISOString().split('T')[0];

const deduped = new Map();
for (const item of allItems) {
  const pid = item.json.project_id;
  if (!deduped.has(pid) || String(item.json.week_start_date) > String(deduped.get(pid).json.week_start_date)) {
    deduped.set(pid, item);
  }
}
const items = Array.from(deduped.values());

const projects = items.map(item => {
  const summary = typeof item.json.summary === 'string'
    ? JSON.parse(item.json.summary || '{}')
    : (item.json.summary || {});
  return {
    project_id: item.json.project_id,
    project_name: item.json.project_name,
    avg_progress: summary.avg_progress || 0,
    progress_trend: summary.progress_trend || 0,
    high_risk_count: (summary.high_risks || []).length,
    risk_counts: summary.risk_counts || {}
  };
});

const totalProjects = projects.length;
const highRiskProjects = projects.filter(p => p.high_risk_count > 0);
const avgProgress = totalProjects > 0
  ? projects.reduce((s, p) => s + p.avg_progress, 0) / totalProjects
  : 0;
const onTrackProjects = projects.filter(p => p.progress_trend >= 0 && p.high_risk_count === 0);

const content = {
  report_week: weekStartStr,
  total_projects: totalProjects,
  on_track_count: onTrackProjects.length,
  high_risk_count: highRiskProjects.length,
  average_progress: Math.round(avgProgress * 100) / 100,
  projects: projects,
  high_risk_projects: highRiskProjects.map(p => p.project_name),
  executive_summary: totalProjects + '件のプロジェクトを管理中。平均進捗率' + Math.round(avgProgress) + '%。順調' + onTrackProjects.length + '件、高リスク' + highRiskProjects.length + '件。'
};

const escapeSql = s => String(s).replace(/'/g, "''");

return [{
  json: {
    report_date: today,
    report_type: 'weekly',
    content_sql: escapeSql(JSON.stringify(content))
  }
}];

const summaryData = $('週次サマリー生成').item.json;
const project = $('プロジェクトループ').item.json;
const summary = JSON.parse(summaryData.summary_sql);
const highRiskCount = (summary.high_risks || []).length;
const riskCounts = summary.risk_counts || {};
const riskLines = Object.entries(riskCounts).map(([type, count]) => '  - ' + type + ': ' + count + '件').join('\n');
const trendSign = summary.progress_trend >= 0 ? '+' : '';
const lines = [
  'あなたはPMO（プロジェクトマネジメントオフィス）担当者です。以下の週次レポートを分析し、次週のアクション判断のための実務的コメントを日本語200〜400字で記述してください。',
  '',
  '【プロジェクト情報】',
  '- プロジェクト名: ' + project.name,
  '- 対象週: ' + summary.week_start + '〜' + summary.week_end,
  '- 週平均進捗率: ' + summary.avg_progress + '%',
  '- 進捗トレンド: ' + trendSign + summary.progress_trend + '%',
  '- 高リスク件数: ' + highRiskCount + '件',
  '',
  '【リスク種別内訳】',
  riskLines || '  リスクなし',
  '',
  '優先対処すべきリスクとその根拠、次週の推奨アクションを簡潔に記述してください。'
];
return [{json: {project_id: summaryData.project_id, week_start_date: summaryData.week_start_date, prompt: lines.join('\n')}}];

const aiOutput = $json.output;
const meta = $('週次PMOプロンプト生成').item.json;
const escapeSql = s => String(s).replace(/'/g, "''");
const comment = escapeSql(aiOutput.trim());
const q = "'";
return [{json: {update_sql: 'UPDATE weekly_reports SET ai_comment = ' + q + comment + q + ' WHERE project_id = ' + meta.project_id + ' AND week_start_date = ' + q + meta.week_start_date + q}}];

const aiOutput = $json.output;
const meta = $('エグゼクティブプロンプト生成').item.json;
const escapeSql = s => String(s).replace(/'/g, "''");
const comment = escapeSql(aiOutput.trim());
const q = "'";
return [{json: {update_sql: 'UPDATE executive_reports SET ai_comment = ' + q + comment + q + ' WHERE report_date = ' + q + meta.report_date + q + ' AND report_type = ' + q + 'weekly' + q}}];
